1	import { useCallback, useEffect, useState } from 'react';
2	import {
3	  KeyboardAvoidingView,
4	  Platform,
5	  StyleSheet,
6	  Text,
7	  TextInput,
8	  View,
9	} from 'react-native';
10	import { BottomSheet } from '@/components/primitives/BottomSheet';
11	import { ButtonPrimary } from '@/components/primitives/Button';
12	import { useToast } from '@/components/primitives/Toast';
13	import { colors, radii, shadows, spacing } from '@/design/tokens';
14	import { textStyles } from '@/design/typography';
15	import { supabase } from '@/lib/supabase';
16	
17	// US-042 — Apply modal on campaign detail. Bottom sheet with an optional
18	// pitch field that calls the apply-to-listing edge function (US-041).
19	//
20	// Spec alignment (docs/design.md §4.3 + docs/tech-architecture.md §5.5):
21	// - Header copy "You're applying to" + listing title
22	// - Pitch (optional) text area with character counter (story AC: 280-char
23	//   cap; design.md mock shows 0/160 — story AC value used; see Spec gap
24	//   in progress.txt for US-042)
25	// - "By applying you confirm you'll follow the campaign rules." disclaimer
26	// - "Send application" CTA
27	//
28	// Edge-function field is `cover_note` per spec §5.5 / `applications.cover_note`
29	// column (the story AC says "pitch" but cover_note is canonical — same
30	// resolution as US-041's edge function).
31	//
32	// Response handling: 200 → onApplied; structured errors decoded via the
33	// FunctionsHttpError context Response (Codebase Pattern #98). For
34	// INELIGIBLE 403 the toast surfaces a one-line summary derived from the
35	// first failed condition; spec-defined 409 codes (LISTING_NOT_ACTIVE,
36	// LISTING_VERSION_CHANGED, ALREADY_APPLIED) and 404 each get their own
37	// toast. The parent reloads the listing for any state-changing error so
38	// the eligibility rail and CTA reflect the new server reality.
39	
40	const COVER_NOTE_MAX_LEN = 280;
41	
42	type SocialPlatform = 'tiktok' | 'instagram';
43	
44	type FailedCondition = {
45	  metric: string;
46	  platform: SocialPlatform | null;
47	  required: number | boolean;
48	  actual: number | boolean | null;
49	};
50	
51	type ApplySuccess = {
52	  application_id: string;
53	  listing_version_id: string;
54	};
55	
56	type ServerErrorBody = {
57	  error?: string;
58	  failed_conditions?: FailedCondition[];
59	  current_version_id?: string;
60	};
61	
62	export type ApplyFailure =
63	  | { kind: 'ineligible' }
64	  | { kind: 'version_changed' }
65	  | { kind: 'already_applied' }
66	  | { kind: 'not_active' }
67	  | { kind: 'not_found' };
68	
69	export type ApplySheetProps = {
70	  visible: boolean;
71	  listingId: string;
72	  listingTitle: string;
73	  onDismiss: () => void;
74	  onApplied: (applicationId: string) => void;
75	  onServerStateChanged: (failure: ApplyFailure) => void;
76	};
77	
78	export function ApplySheet({
79	  visible,
80	  listingId,
81	  listingTitle,
82	  onDismiss,
83	  onApplied,
84	  onServerStateChanged,
85	}: ApplySheetProps) {
86	  const { show: showToast } = useToast();
87	  const [pitch, setPitch] = useState('');
88	  const [submitting, setSubmitting] = useState(false);
89	
90	  // Reset the pitch + submitting flags whenever the sheet re-opens, so a prior
91	  // half-typed message doesn't leak into a fresh attempt.
92	  useEffect(() => {
93	    if (visible) {
94	      setPitch('');
95	      setSubmitting(false);
96	    }
97	  }, [visible]);
98	
99	  const onSubmit = useCallback(async () => {
100	    if (submitting) return;
101	    setSubmitting(true);
102	    const trimmed = pitch.trim();
103	    try {
104	      const { data, error } = await supabase.functions.invoke<ApplySuccess>(
105	        'apply-to-listing',
106	        {
107	          body: {
108	            listing_id: listingId,
109	            ...(trimmed.length > 0 ? { cover_note: trimmed } : {}),
110	          },
111	        },
112	      );
113	
114	      if (error) {
115	        const body = await readErrorBody(error);
116	        const failure = mapErrorBodyToFailure(body);
117	        if (failure) {
118	          showToast({
119	            message: toastForFailure(failure, body),
120	            variant: failure.kind === 'already_applied' ? 'info' : 'error',
121	          });
122	          onServerStateChanged(failure);
123	          return;
124	        }
125	        showToast({
126	          message: 'Could not send application. Try again.',
127	          variant: 'error',
128	        });
129	        return;
130	      }
131	
132	      if (!data?.application_id) {
133	        showToast({
134	          message: 'Could not send application. Try again.',
135	          variant: 'error',
136	        });
137	        return;
138	      }
139	
140	      onApplied(data.application_id);
141	    } catch (err) {
142	      console.error('apply-to-listing threw', err);
143	      showToast({
144	        message: 'Could not send application. Try again.',
145	        variant: 'error',
146	      });
147	    } finally {
148	      setSubmitting(false);
149	    }
150	  }, [pitch, listingId, submitting, showToast, onApplied, onServerStateChanged]);
151	
152	  const remaining = COVER_NOTE_MAX_LEN - pitch.length;
153	  const overLimit = remaining < 0;
154	
155	  return (
156	    <BottomSheet
157	      visible={visible}
158	      onDismiss={onDismiss}
159	      snapPoints={[0.7]}
160	      accessibilityLabel="Apply to campaign"
161	      testID="apply-sheet"
162	    >
163	      <KeyboardAvoidingView
164	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
165	        style={styles.flex}
166	      >
167	        <View style={styles.header}>
168	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
169	            You&apos;re applying to
170	          </Text>
171	          <Text
172	            style={[textStyles.h1, { color: colors.ink }]}
173	            numberOfLines={2}
174	            testID="apply-sheet-title"
175	          >
176	            {listingTitle}
177	          </Text>
178	        </View>
179	
180	        <View style={styles.fieldGroup}>
181	          <View style={styles.labelRow}>
182	            <Text style={[textStyles.caption, { color: colors.ink70 }]}>
183	              Pitch (optional)
184	            </Text>
185	            <Text
186	              style={[
187	                textStyles.caption,
188	                { color: overLimit ? colors.danger : colors.ink40 },
189	              ]}
190	              testID="apply-sheet-counter"
191	            >
192	              {pitch.length}/{COVER_NOTE_MAX_LEN}
193	            </Text>
194	          </View>
195	          <View
196	            style={[
197	              styles.inputWrap,
198	              shadows.hard,
199	              overLimit && styles.inputWrapError,
200	            ]}
201	          >
202	            <TextInput
203	              value={pitch}
204	              onChangeText={setPitch}
205	              placeholder="Why are you a fit?"
206	              placeholderTextColor={colors.ink40}
207	              multiline
208	              maxLength={COVER_NOTE_MAX_LEN + 40}
209	              style={[textStyles.body, styles.input]}
210	              accessibilityLabel="Pitch"
211	              testID="apply-sheet-pitch"
212	            />
213	          </View>
214	        </View>
215	
216	        <Text style={[textStyles.caption, styles.disclaimer]}>
217	          By applying you confirm you&apos;ll follow the campaign rules.
218	        </Text>
219	
220	        <View style={styles.cta}>
221	          <ButtonPrimary
222	            label="Send application"
223	            onPress={onSubmit}
224	            loading={submitting}
225	            disabled={submitting || overLimit}
226	            testID="apply-sheet-submit"
227	          />
228	        </View>
229	      </KeyboardAvoidingView>
230	    </BottomSheet>
231	  );
232	}
233	
234	async function readErrorBody(
235	  error: unknown,
236	): Promise<ServerErrorBody | null> {
237	  const ctx = (error as { context?: unknown }).context;
238	  if (
239	    !ctx ||
240	    typeof ctx !== 'object' ||
241	    !('status' in ctx) ||
242	    typeof (ctx as { json?: unknown }).json !== 'function'
243	  ) {
244	    return null;
245	  }
246	  try {
247	    return (await (ctx as Response).json()) as ServerErrorBody;
248	  } catch {
249	    return null;
250	  }
251	}
252	
253	function mapErrorBodyToFailure(
254	  body: ServerErrorBody | null,
255	): ApplyFailure | null {
256	  if (!body?.error) return null;
257	  switch (body.error) {
258	    case 'INELIGIBLE':
259	      return { kind: 'ineligible' };
260	    case 'LISTING_VERSION_CHANGED':
261	      return { kind: 'version_changed' };
262	    case 'ALREADY_APPLIED':
263	      return { kind: 'already_applied' };
264	    case 'LISTING_NOT_ACTIVE':
265	      return { kind: 'not_active' };
266	    case 'LISTING_NOT_FOUND':
267	      return { kind: 'not_found' };
268	    default:
269	      return null;
270	  }
271	}
272	
273	function toastForFailure(
274	  failure: ApplyFailure,
275	  body: ServerErrorBody | null,
276	): string {
277	  switch (failure.kind) {
278	    case 'ineligible': {
279	      const first = body?.failed_conditions?.[0];
280	      return first
281	        ? `You no longer meet ${conditionLabel(first)}.`
282	        : 'You no longer meet this campaign\u2019s requirements.';
283	    }
284	    case 'version_changed':
285	      return 'This campaign was updated. Refreshing the details.';
286	    case 'already_applied':
287	      return 'You\u2019ve already applied to this campaign.';
288	    case 'not_active':
289	      return 'This campaign is no longer accepting applications.';
290	    case 'not_found':
291	      return 'This campaign is no longer available.';
292	  }
293	}
294	
295	function conditionLabel(f: FailedCondition): string {
296	  const platform = f.platform ? platformLabel(f.platform) : '';
297	  const base = metricLabel(f.metric);
298	  return platform ? `${platform} ${base}` : base;
299	}
300	
301	function platformLabel(p: SocialPlatform): string {
302	  return p === 'tiktok' ? 'TikTok' : 'Instagram';
303	}
304	
305	function metricLabel(metric: string): string {
306	  switch (metric) {
307	    case 'min_followers':
308	      return 'minimum followers';
309	    case 'min_avg_views_last_n':
310	      return 'avg views (last 10)';
311	    case 'min_total_likes':
312	      return 'total likes';
313	    case 'min_videos_posted':
314	      return 'videos posted';
315	    case 'verified_only':
316	      return 'verified account';
317	    default:
318	      return metric;
319	  }
320	}
321	
322	const styles = StyleSheet.create({
323	  flex: { flex: 1 },
324	  header: {
325	    gap: spacing.xs,
326	    marginBottom: spacing.lg,
327	  },
328	  fieldGroup: {
329	    gap: spacing.sm,
330	  },
331	  labelRow: {
332	    flexDirection: 'row',
333	    justifyContent: 'space-between',
334	    alignItems: 'baseline',
335	  },
336	  inputWrap: {
337	    backgroundColor: colors.surface,
338	    borderRadius: radii.input,
339	    borderWidth: 2,
340	    borderColor: colors.ink,
341	  },
342	  inputWrapError: {
343	    borderColor: colors.danger,
344	  },
345	  input: {
346	    minHeight: 110,
347	    paddingHorizontal: spacing.base,
348	    paddingVertical: spacing.md,
349	    color: colors.ink,
350	    textAlignVertical: 'top',
351	  },
352	  disclaimer: {
353	    color: colors.ink70,
354	    marginTop: spacing.lg,
355	  },
356	  cta: {
357	    marginTop: 'auto',
358	    paddingTop: spacing.lg,
359	  },
360	});
