1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  Linking,
5	  Pressable,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  View,
11	} from 'react-native';
12	import { router, useLocalSearchParams } from 'expo-router';
13	import { Check, ChevronLeft, ExternalLink, X } from 'lucide-react-native';
14	import { ButtonPrimary } from '@/components/primitives/Button';
15	import { StatusPill } from '@/components/primitives/StatusPill';
16	import { useToast } from '@/components/primitives/Toast';
17	import { colors, radii, shadows, spacing } from '@/design/tokens';
18	import { textStyles } from '@/design/typography';
19	import { supabase } from '@/lib/supabase';
20	import type { Database } from '@/types/supabase';
21	import { ApplySheet, type ApplyFailure } from '@/screens/listing-detail/ApplySheet';
22	
23	// US-040 — Campaign detail screen. Gated under the creator tab group so
24	// the shared TabBar stays visible; route matches the story AC
25	// (`app/(creator)/listing/[id].tsx`). Data flows through the
26	// get-listing-detail edge function (US-039) — that path is picked
27	// deliberately over direct PostgREST so it works around the current
28	// JWT-drift cascade that blocks gateway-verified table reads.
29	//
30	// Spec alignment (docs/design.md §4.2):
31	// - Back chevron header (lister handle deferred — requires a lister-profile
32	//   join the edge function does not yet expose; Spec gap noted in progress.txt).
33	// - Hero card with title, price, "Payout after approval" caption.
34	// - Sample videos rendered as tappable rows that open the URL in the
35	//   platform app via Linking.openURL — NOT embedded previews per the
36	//   design doc's "link-out only" v1 rule.
37	// - Eligibility rail: one row per PRE condition showing ✓/✗ plus the
38	//   required threshold and the creator's actual value (from the
39	//   edge-function `failed_conditions` additive `actual` field).
40	// - "What to film" post-condition bullet list (POST rows; not gated on
41	//   eligibility — reviewed at submission time, US-057+).
42	// - Sticky footer with the Apply CTA. Gate per §4.2:
43	//     eligible + !active-app  → ButtonPrimary "Apply to collab"
44	//     eligible + active-app   → StatusPill + disabled CTA
45	//     ineligible              → disabled CTA "Not eligible yet"
46	//     inactive listing        → no CTA, status banner at top
47	//
48	// Apply flow: tapping the CTA opens the ApplySheet (US-042) which posts
49	// to apply-to-listing (US-041). On success we toast + route to the
50	// Applied tab; on a server-state change (version bump, paused listing,
51	// already-applied, ineligible, not-found) we close the sheet and reload
52	// the detail so the eligibility rail / CTA reflect the new reality.
53	
54	type ListingRow = Database['public']['Tables']['listings']['Row'];
55	type ConditionRow = Database['public']['Tables']['listing_conditions']['Row'];
56	type SampleVideoRow = Database['public']['Tables']['sample_videos']['Row'];
57	type Platform = Database['public']['Enums']['platform'];
58	type ListingStatus = Database['public']['Enums']['listing_status'];
59	
60	type FailedCondition = {
61	  metric: string;
62	  platform: Platform | null;
63	  required: number | boolean;
64	  actual: number | boolean | null;
65	};
66	
67	type DetailResponse = {
68	  listing: ListingRow;
69	  conditions: ConditionRow[];
70	  sample_videos: SampleVideoRow[];
71	  eligibility: {
72	    eligible: boolean;
73	    failed_conditions: FailedCondition[];
74	    has_active_application: boolean;
75	  };
76	};
77	
78	type LoadState =
79	  | { kind: 'loading' }
80	  | { kind: 'error'; code: 'not_found' | 'generic' }
81	  | { kind: 'ok'; data: DetailResponse };
82	
83	export default function ListingDetail() {
84	  const { id } = useLocalSearchParams<{ id: string }>();
85	  const { show: showToast } = useToast();
86	  const [state, setState] = useState<LoadState>({ kind: 'loading' });
87	  const [applySheetOpen, setApplySheetOpen] = useState(false);
88	
89	  const load = useCallback(async () => {
90	    if (!id) {
91	      setState({ kind: 'error', code: 'not_found' });
92	      return;
93	    }
94	    setState({ kind: 'loading' });
95	    const { data, error } = await supabase.functions.invoke<DetailResponse>(
96	      'get-listing-detail',
97	      { body: { listing_id: id } },
98	    );
99	    if (error) {
100	      const ctx = (error as { context?: unknown }).context;
101	      if (
102	        ctx &&
103	        typeof ctx === 'object' &&
104	        'status' in ctx &&
105	        typeof (ctx as { json?: unknown }).json === 'function'
106	      ) {
107	        const res = ctx as Response;
108	        if (res.status === 404) {
109	          setState({ kind: 'error', code: 'not_found' });
110	          return;
111	        }
112	      }
113	      console.error('get-listing-detail failed', error);
114	      setState({ kind: 'error', code: 'generic' });
115	      return;
116	    }
117	    if (!data) {
118	      setState({ kind: 'error', code: 'generic' });
119	      return;
120	    }
121	    setState({ kind: 'ok', data });
122	  }, [id]);
123	
124	  useEffect(() => {
125	    void load();
126	  }, [load]);
127	
128	  const onBack = useCallback(() => {
129	    // Slot-based layouts don't maintain a full stack, so fall back to
130	    // the feed when back is unavailable (Codebase Pattern #27/#95).
131	    if (router.canGoBack()) {
132	      router.back();
133	    } else {
134	      router.replace('/(creator)/feed');
135	    }
136	  }, []);
137	
138	  const onApply = useCallback(() => {
139	    setApplySheetOpen(true);
140	  }, []);
141	
142	  const onApplied = useCallback(() => {
143	    setApplySheetOpen(false);
144	    showToast({
145	      message: 'Application sent.',
146	      variant: 'success',
147	    });
148	    // Per AC: route to the Applied tab. The actual route is
149	    // `/(creator)/applications` (US-031 layout); the AC's "(creator)/applied"
150	    // refers to the same logical tab.
151	    router.replace('/(creator)/applications');
152	  }, [showToast]);
153	
154	  const onApplyFailure = useCallback(
155	    (failure: ApplyFailure) => {
156	      setApplySheetOpen(false);
157	      // Reload so the eligibility rail / CTA reflect the new server reality
158	      // (version bumped, listing paused, an existing application surfaced, etc.).
159	      if (
160	        failure.kind === 'version_changed' ||
161	        failure.kind === 'not_active' ||
162	        failure.kind === 'already_applied' ||
163	        failure.kind === 'ineligible' ||
164	        failure.kind === 'not_found'
165	      ) {
166	        void load();
167	      }
168	    },
169	    [load],
170	  );
171	
172	  const listingTitle = state.kind === 'ok' ? state.data.listing.title : '';
173	
174	  return (
175	    <SafeAreaView style={styles.container}>
176	      <Header onBack={onBack} />
177	      {state.kind === 'loading' ? (
178	        <View style={styles.centered}>
179	          <ActivityIndicator color={colors.ink} />
180	        </View>
181	      ) : state.kind === 'error' ? (
182	        <ErrorBody code={state.code} onBack={onBack} />
183	      ) : (
184	        <DetailBody data={state.data} onApply={onApply} />
185	      )}
186	      {id ? (
187	        <ApplySheet
188	          visible={applySheetOpen}
189	          listingId={id}
190	          listingTitle={listingTitle}
191	          onDismiss={() => setApplySheetOpen(false)}
192	          onApplied={onApplied}
193	          onServerStateChanged={onApplyFailure}
194	        />
195	      ) : null}
196	    </SafeAreaView>
197	  );
198	}
199	
200	function Header({ onBack }: { onBack: () => void }) {
201	  return (
202	    <View style={styles.header}>
203	      <Pressable
204	        onPress={onBack}
205	        hitSlop={spacing.md}
206	        accessibilityRole="button"
207	        accessibilityLabel="Back"
208	        testID="listing-back"
209	      >
210	        <ChevronLeft color={colors.ink} size={28} strokeWidth={2.5} />
211	      </Pressable>
212	      <Text style={[textStyles.h2, { color: colors.ink }]}>Campaign</Text>
213	      <View style={styles.headerSpacer} />
214	    </View>
215	  );
216	}
217	
218	function ErrorBody({
219	  code,
220	  onBack,
221	}: {
222	  code: 'not_found' | 'generic';
223	  onBack: () => void;
224	}) {
225	  const copy =
226	    code === 'not_found'
227	      ? 'This campaign is no longer available.'
228	      : 'Could not load this campaign. Try again in a moment.';
229	  return (
230	    <View style={styles.centered}>
231	      <Text style={[textStyles.h1, { color: colors.ink, textAlign: 'center' }]}>
232	        Campaign not found
233	      </Text>
234	      <Text
235	        style={[textStyles.body, { color: colors.ink70, textAlign: 'center', marginTop: spacing.sm }]}
236	      >
237	        {copy}
238	      </Text>
239	      <View style={{ marginTop: spacing.xl, minWidth: 160 }}>
240	        <ButtonPrimary label="Back to feed" onPress={onBack} testID="listing-error-back" />
241	      </View>
242	    </View>
243	  );
244	}
245	
246	function DetailBody({
247	  data,
248	  onApply,
249	}: {
250	  data: DetailResponse;
251	  onApply: () => void;
252	}) {
253	  const { listing, conditions, sample_videos, eligibility } = data;
254	
255	  const preConditions = useMemo(
256	    () => conditions.filter((c) => c.kind === 'pre'),
257	    [conditions],
258	  );
259	  const postConditions = useMemo(
260	    () => conditions.filter((c) => c.kind === 'post'),
261	    [conditions],
262	  );
263	
264	  const failureByKey = useMemo(() => {
265	    const map = new Map<string, FailedCondition>();
266	    for (const f of eligibility.failed_conditions) {
267	      map.set(conditionKey(f.metric, f.platform), f);
268	    }
269	    return map;
270	  }, [eligibility.failed_conditions]);
271	
272	  const inactiveBanner = getInactiveBanner(listing.status);
273	  const priceLabel = formatPrice(listing.price_cents, listing.currency);
274	
275	  return (
276	    <>
277	      <ScrollView
278	        contentContainerStyle={styles.scrollContent}
279	        showsVerticalScrollIndicator={false}
280	      >
281	        {inactiveBanner ? (
282	          <View style={styles.inactiveBanner} testID="listing-inactive-banner">
283	            <Text style={[textStyles.caption, { color: colors.ink }]}>
284	              {inactiveBanner}
285	            </Text>
286	          </View>
287	        ) : null}
288	
289	        <View style={styles.heroCard} testID="listing-hero">
290	          <Text style={[textStyles.display, { color: colors.ink }]}>
291	            {listing.title}
292	          </Text>
293	          <Text style={[textStyles.h1, styles.priceRow]} testID="listing-price">
294	            {priceLabel}
295	          </Text>
296	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
297	            Payout after approval
298	          </Text>
299	        </View>
300	
301	        {sample_videos.length > 0 ? (
302	          <Section title="Sample videos">
303	            <View style={styles.sampleList}>
304	              {sample_videos.map((v) => (
305	                <SampleVideoCell key={v.id} video={v} />
306	              ))}
307	            </View>
308	          </Section>
309	        ) : null}
310	
311	        {preConditions.length > 0 ? (
312	          <Section title="Eligibility">
313	            <View style={styles.eligibilityList}>
314	              {preConditions.map((c) => (
315	                <EligibilityRow
316	                  key={c.id}
317	                  condition={c}
318	                  failure={failureByKey.get(conditionKey(c.metric, c.platform)) ?? null}
319	                />
320	              ))}
321	            </View>
322	          </Section>
323	        ) : null}
