631	function formatCount(n: number): string {
632	  if (n < 1000) return String(n);
633	  const trim = (value: number, digits: number): string => {
634	    const fixed = value.toFixed(digits);
635	    return fixed.endsWith('.0') ? fixed.slice(0, -2) : fixed;
636	  };
637	  if (n < 1_000_000) return `${trim(n / 1000, n < 10_000 ? 1 : 0)}k`;
638	  if (n < 1_000_000_000) return `${trim(n / 1_000_000, n < 10_000_000 ? 1 : 0)}m`;
639	  return `${trim(n / 1_000_000_000, n < 10_000_000_000 ? 1 : 0)}b`;
640	}
