186	  root: {
187	    flex: 1,
188	    justifyContent: 'flex-end',
189	  },
190	  backdrop: {
191	    ...StyleSheet.absoluteFillObject,
192	    backgroundColor: colors.ink,
193	  },
194	  sheet: {
195	    backgroundColor: colors.canvas,
196	    borderTopLeftRadius: radii.card,
197	    borderTopRightRadius: radii.card,
198	    borderWidth: 2,
199	    borderBottomWidth: 0,
200	    borderColor: colors.ink,
201	    paddingTop: spacing.sm,
202	  },
203	  handle: {
204	    alignSelf: 'center',
205	    width: 48,
206	    height: 4,
207	    borderRadius: radii.pill,
208	    backgroundColor: colors.ink40,
209	    marginBottom: spacing.sm,
210	  },
211	  content: {
212	    flex: 1,
213	    paddingHorizontal: spacing.xl,
